import{_ as t,o as e,c as l,ag as i}from"./chunks/framework.CAXxHpAX.js";const q=JSON.parse('{"title":"飞书知识库集成","description":"","frontmatter":{},"headers":[],"relativePath":"05-feishu.md","filePath":"05-feishu.md"}'),r={name:"05-feishu.md"};function o(n,a,h,s,d,u){return e(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="飞书知识库集成" tabindex="-1">飞书知识库集成 <a class="header-anchor" href="#飞书知识库集成" aria-label="Permalink to &quot;飞书知识库集成&quot;">​</a></h1><p>来源：<a href="https://mp.weixin.qq.com/s?__biz=MzE5MTY3MTY4OA==&amp;mid=2247484720&amp;idx=1&amp;sn=905903b760774fa5b1e4b72a7e1b6ec5" target="_blank" rel="noreferrer">二师兄的AIDao - Hermes Agent 最好的知识库可能就是飞书知识库</a></p><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><blockquote><p>没有知识库的 Agent 很聪明，有知识库的 Agent 才开始真正有用。 聊天框更像即时响应层，知识库才是把上下文、草稿、记录和复盘接住的系统层。</p></blockquote><h2 id="聊天框的局限" tabindex="-1">聊天框的局限 <a class="header-anchor" href="#聊天框的局限" aria-label="Permalink to &quot;聊天框的局限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>快</td><td>散（信息分散）</td></tr><tr><td>轻</td><td>浅（不擅长长期管理）</td></tr></tbody></table><ul><li>聊天框能推动事情<strong>开始</strong>，却不擅长接住事情<strong>结束</strong></li><li>聊天框能保留文字，却不天然保留结构</li></ul><h2 id="为什么飞书适合-hermes" tabindex="-1">为什么飞书适合 Hermes <a class="header-anchor" href="#为什么飞书适合-hermes" aria-label="Permalink to &quot;为什么飞书适合 Hermes&quot;">​</a></h2><ol><li><strong>接住工作流</strong>：不只是存东西，而是承接流程（选题池、草稿中心、图片中心、发布记录、效果复盘、内容基因库）</li><li><strong>人和 Agent 一起工作</strong>：飞书既是 Agent 能写入的地方，也是人能直接协作的地方</li><li><strong>同时承接文档和结构化数据</strong>： <ul><li><strong>Docx</strong> 负责草稿、规范和复盘</li><li><strong>Bitable</strong> 负责状态、记录与指标</li></ul></li><li><strong>让 Agent 的结果有落点</strong>：不再是一次性使用，而是进入草稿页、选题池、发布记录、复盘页、内容基因库</li></ol><h2 id="内容系统架构" tabindex="-1">内容系统架构 <a class="header-anchor" href="#内容系统架构" aria-label="Permalink to &quot;内容系统架构&quot;">​</a></h2><h3 id="选题池" tabindex="-1">选题池 <a class="header-anchor" href="#选题池" aria-label="Permalink to &quot;选题池&quot;">​</a></h3><p>可状态化管理的 Bitable，关联方向、状态、优先级、后续草稿、发布情况。内容从&quot;灵感驱动&quot;变成&quot;系统推进&quot;。</p><h3 id="草稿中心" tabindex="-1">草稿中心 <a class="header-anchor" href="#草稿中心" aria-label="Permalink to &quot;草稿中心&quot;">​</a></h3><p>每篇文章有自己的正式草稿页：</p><ul><li>标题候选</li><li>文章导语</li><li>正文版本</li><li>配图位</li><li>审核意见</li><li>发布备注</li></ul><h3 id="图片中心" tabindex="-1">图片中心 <a class="header-anchor" href="#图片中心" aria-label="Permalink to &quot;图片中心&quot;">​</a></h3><p>封面图风格、标题排布、视觉元素、配色逻辑、点击感知可记录复用。图片从&quot;一次一张用完就算&quot;变成可复盘的资产。</p><h3 id="发布记录" tabindex="-1">发布记录 <a class="header-anchor" href="#发布记录" aria-label="Permalink to &quot;发布记录&quot;">​</a></h3><p>发布时间、标题版本、封面版本、对应链接、后续数据，进入结构化记录。</p><h3 id="效果复盘" tabindex="-1">效果复盘 <a class="header-anchor" href="#效果复盘" aria-label="Permalink to &quot;效果复盘&quot;">​</a></h3><ul><li>这篇为什么点开？</li><li>为什么没点开？</li><li>标题起了什么作用？</li><li>封面图有没有拖后腿？</li><li>导语是不是太慢？</li><li>哪种表达方式更有传播性？</li></ul><h3 id="内容基因库" tabindex="-1">内容基因库 <a class="header-anchor" href="#内容基因库" aria-label="Permalink to &quot;内容基因库&quot;">​</a></h3><p>真正有价值的内容经验沉淀：</p><ul><li>哪种标题结构更容易点开</li><li>哪种开头更容易把人带进去</li><li>哪种转折更像&quot;能转发的公众号内容&quot;</li><li>哪种 CTA 更自然</li><li>哪种图更像这个号的风格</li></ul><h2 id="真正改变的是什么" tabindex="-1">真正改变的是什么 <a class="header-anchor" href="#真正改变的是什么" aria-label="Permalink to &quot;真正改变的是什么&quot;">​</a></h2><ul><li>内容不再是一篇一篇孤立生产，而是可以连续推进的系统</li><li>经验不再停留在人脑里，而是进入可复用、可检索、可更新的知识结构</li><li>Agent 不再只是临时帮忙，而是参与选题、起稿、改写、同步、记录、复盘</li><li>团队不再只是&quot;用 AI 写稿&quot;，而是真正拥有<strong>人和 Agent 一起协作的内容工作流</strong></li></ul><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><blockquote><p>Hermes Agent 最好的知识库，可能不是那个功能表最华丽的知识库，而是那个最能接住它工作结果的知识库。</p></blockquote><p>飞书知识库能同时做到三件事：</p><ol><li><strong>接住上下文</strong></li><li><strong>接住协作过程</strong></li><li><strong>接住长期资产</strong></li></ol><p>这三件事叠在一起，才真正构成 Agent 的&quot;外部大脑&quot;。</p>',31)])])}const b=t(r,[["render",o]]);export{q as __pageData,b as default};
